{
  "artefact_id": "ddd-context-map-shop-2026-05-23",
  "owner": "Ruslan Faion <ruslan@faion.net>",
  "version": "1.0.0",
  "last_reviewed": "2026-05-23",
  "bounded_contexts": [
    {
      "name": "Catalog"
    },
    {
      "name": "Ordering"
    }
  ],
  "aggregates": [
    {
      "context": "Ordering",
      "name": "Order",
      "invariants": [
        "total = sum(lines)"
      ]
    }
  ],
  "domain_events": [
    {
      "name": "OrderSubmitted",
      "owner": "Ordering"
    }
  ],
  "glossary": [
    {
      "term": "Order",
      "definition": "Submitted basket"
    },
    {
      "term": "LineItem",
      "definition": "Product + qty"
    },
    {
      "term": "Item",
      "definition": "SKU + price"
    },
    {
      "term": "Cart",
      "definition": "Pre-order basket"
    },
    {
      "term": "Refund",
      "definition": "Reversal of payment"
    }
  ]
}
